class User {
  constructor(name, email) {
    this.name = name;
    this.email = email;
  }

  getName() {
    return this.name;
  }

  getEmail() {
    return this.email;
  }

  // TODO: 这个方法应该移到auth.js中
  validatePassword(password) {
    return password.length >= 8;
  }
}

